export const heroById = (id) => CHAMPIONS_100.find((c) => c.id === id) || null;
export const heroesByLane = (lane) => CHAMPIONS_100.filter((c) => c.lane === lane);
export const heroesByArch = (arch) => CHAMPIONS_100.filter((c) => c.arch === arch);
export const ARCHETYPES = ["坦克", "戰士", "刺客", "法師", "射手", "輔助"];
export const LANES = ["上路", "打野", "中路", "下路", "輔助"];

// ── Hero 圖片（Sprint20 A）───────────────────────────────────────────────────
// 圖片資源表 data/heroImages.js（Legacy HERO_IMG 抽取）由本檔統一對外，
// heroDatabase 仍是唯一 Hero Database；UI 只准用下列函式取圖，不得直接 import 資源表。
// 查無圖片 → 回 null，呼叫端一律走程序化色塊 fallback（不得破圖）。
export const heroImage = (id) => HERO_IMAGES[id] ?? null;
export const heroPortrait = (id) => HERO_IMAGES[id] ?? null;   // 同義別名（語意：頭像用途）
export const hasHeroImage = (id) => Boolean(HERO_IMAGES[id]);
